# Category: information_disclosure

import Foundation
import UIKit
import CoreData

class AnalyticsManager {
    static let shared = AnalyticsManager()
    
    private init() {}
    
    func logInteraction(_ interactionType: String, _ data: Any?) {
        NSLog("User Interaction: \(interactionType)")
        
        if let data = data as? [String: Any] {
            for (key, value) in data {
                print("\(key): \(value)")
            }
        }
    }
    
    func logAPICall(_ apiName: String, _ requestData: Data?, _ responseData: Data?) {
        NSLog("API Call: \(apiName)")
        
        if let requestData = requestData {
            print("Request Data: \(requestData)")
        }
        
        if let responseData = responseData {
            print("Response Data: \(responseData)")
        }
    }
    
    func logUserDataChange(_ userID: String, _ emailAddress: String, _ token: String) {
        NSLog("User Data Change: User ID = \(userID), Email Address = \(emailAddress), Token = \(token)")
    }
    
    func logErrorCondition(_ error: Error) {
        NSLog("Error Condition: \(error.localizedDescription)")
    }
}